/**
 * API Dedup Testing Suite
 * Tests for request deduplication and data deduplication
 */

// Simple in-memory request dedup cache
class RequestDeduplicator {
  constructor() {
    this.cache = new Map();
    this.pending = new Map();
  }

  // Generate cache key from request parameters
  getCacheKey(method, url, params = {}) {
    return `${method}:${url}:${JSON.stringify(params)}`;
  }

  // Deduplicate concurrent requests
  async dedupRequest(method, url, params, fetchFn) {
    const key = this.getCacheKey(method, url, params);

    // If request already in progress, wait for it
    if (this.pending.has(key)) {
      return this.pending.get(key);
    }

    // If cached, return cached result
    if (this.cache.has(key)) {
      return this.cache.get(key);
    }

    // Make new request and cache it
    const promise = fetchFn(method, url, params)
      .then(result => {
        this.cache.set(key, result);
        this.pending.delete(key);
        return result;
      })
      .catch(error => {
        this.pending.delete(key);
        throw error;
      });

    this.pending.set(key, promise);
    return promise;
  }

  clear() {
    this.cache.clear();
    this.pending.clear();
  }
}

// Data deduplication utility
class DataDeduplicator {
  // Deduplicate array by unique field
  static deduplicateByField(items, fieldName) {
    const seen = new Set();
    return items.filter(item => {
      const value = item[fieldName];
      if (seen.has(value)) {
        return false;
      }
      seen.add(value);
      return true;
    });
  }

  // Deduplicate array of objects by multiple fields
  static deduplicateByFields(items, fieldNames) {
    const seen = new Set();
    return items.filter(item => {
      const key = fieldNames.map(f => item[f]).join(':');
      if (seen.has(key)) {
        return false;
      }
      seen.add(key);
      return true;
    });
  }

  // Deduplicate and merge duplicate records
  static deduplicateAndMerge(items, idField) {
    const map = new Map();
    items.forEach(item => {
      const id = item[idField];
      if (map.has(id)) {
        map.set(id, { ...map.get(id), ...item });
      } else {
        map.set(id, item);
      }
    });
    return Array.from(map.values());
  }
}

// ============== TESTS ==============

describe('RequestDeduplicator', () => {
  let dedup;
  let mockFetch;
  let callCount;

  beforeEach(() => {
    dedup = new RequestDeduplicator();
    callCount = 0;
    mockFetch = (method, url, params) => {
      callCount++;
      return new Promise(resolve => {
        setTimeout(() => resolve({ data: 'result', callNumber: callCount }), 10);
      });
    };
  });

  test('should cache successful requests', async () => {
    const result1 = await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);
    const result2 = await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);

    expect(callCount).toBe(1);
    expect(result1).toEqual(result2);
    expect(result1.callNumber).toBe(1);
    expect(result2.callNumber).toBe(1);
  });

  test('should deduplicate concurrent identical requests', async () => {
    const promises = [
      dedup.dedupRequest('GET', '/api/users', {}, mockFetch),
      dedup.dedupRequest('GET', '/api/users', {}, mockFetch),
      dedup.dedupRequest('GET', '/api/users', {}, mockFetch),
    ];

    const results = await Promise.all(promises);

    expect(callCount).toBe(1);
    expect(results[0]).toEqual(results[1]);
    expect(results[1]).toEqual(results[2]);
  });

  test('should not deduplicate different URLs', async () => {
    await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);
    await dedup.dedupRequest('GET', '/api/posts', {}, mockFetch);

    expect(callCount).toBe(2);
  });

  test('should not deduplicate different methods', async () => {
    await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);
    await dedup.dedupRequest('POST', '/api/users', {}, mockFetch);

    expect(callCount).toBe(2);
  });

  test('should not deduplicate different parameters', async () => {
    await dedup.dedupRequest('GET', '/api/users', { id: 1 }, mockFetch);
    await dedup.dedupRequest('GET', '/api/users', { id: 2 }, mockFetch);

    expect(callCount).toBe(2);
  });

  test('should clear cache', async () => {
    await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);
    dedup.clear();
    await dedup.dedupRequest('GET', '/api/users', {}, mockFetch);

    expect(callCount).toBe(2);
  });

  test('should handle failed requests', async () => {
    const failingFetch = () => Promise.reject(new Error('Network error'));

    try {
      await dedup.dedupRequest('GET', '/api/users', {}, failingFetch);
    } catch (e) {
      expect(e.message).toBe('Network error');
    }

    // Should not cache failed request, so next request should retry
    try {
      await dedup.dedupRequest('GET', '/api/users', {}, failingFetch);
    } catch (e) {
      expect(e.message).toBe('Network error');
    }
  });
});

describe('DataDeduplicator', () => {
  test('should deduplicate by single field', () => {
    const items = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
      { id: 1, name: 'Alice' },
      { id: 3, name: 'Charlie' },
    ];

    const deduped = DataDeduplicator.deduplicateByField(items, 'id');

    expect(deduped).toHaveLength(3);
    expect(deduped.map(i => i.id)).toEqual([1, 2, 3]);
  });

  test('should preserve first occurrence when deduplicating', () => {
    const items = [
      { id: 1, name: 'Alice', age: 25 },
      { id: 1, name: 'Alice', age: 30 },
    ];

    const deduped = DataDeduplicator.deduplicateByField(items, 'id');

    expect(deduped).toHaveLength(1);
    expect(deduped[0].age).toBe(25);
  });

  test('should deduplicate by multiple fields', () => {
    const items = [
      { userId: 1, postId: 'a', name: 'Comment 1' },
      { userId: 1, postId: 'b', name: 'Comment 2' },
      { userId: 1, postId: 'a', name: 'Comment 1 dup' },
      { userId: 2, postId: 'a', name: 'Comment 3' },
    ];

    const deduped = DataDeduplicator.deduplicateByFields(items, ['userId', 'postId']);

    expect(deduped).toHaveLength(3);
  });

  test('should deduplicate and merge records', () => {
    const items = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob' },
      { id: 1, phone: '555-1234' },
    ];

    const merged = DataDeduplicator.deduplicateAndMerge(items, 'id');

    expect(merged).toHaveLength(2);
    expect(merged.find(i => i.id === 1)).toEqual({
      id: 1,
      name: 'Alice',
      email: 'alice@example.com',
      phone: '555-1234',
    });
  });

  test('should handle empty arrays', () => {
    const deduped = DataDeduplicator.deduplicateByField([], 'id');
    expect(deduped).toEqual([]);
  });

  test('should handle arrays with no duplicates', () => {
    const items = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];

    const deduped = DataDeduplicator.deduplicateByField(items, 'id');

    expect(deduped).toEqual(items);
  });
});

// Integration test
describe('API Dedup Integration', () => {
  test('should deduplicate requests and return consistent data', async () => {
    const dedup = new RequestDeduplicator();
    const apiCall = (method, url) => {
      return Promise.resolve({
        users: [
          { id: 1, name: 'Alice' },
          { id: 1, name: 'Alice' },
          { id: 2, name: 'Bob' },
        ],
      });
    };

    // Make concurrent requests
    const [result1, result2] = await Promise.all([
      dedup.dedupRequest('GET', '/api/users', {}, apiCall),
      dedup.dedupRequest('GET', '/api/users', {}, apiCall),
    ]);

    // Deduplicate the response data
    const deduplicatedUsers = DataDeduplicator.deduplicateByField(
      result1.users,
      'id'
    );

    expect(deduplicatedUsers).toHaveLength(2);
    expect(result1).toEqual(result2);
  });
});

